class Solution {
public:
    vector<int> dailyTemperatures(vector<int>& T) {
        int n=T.size(); vector<int> ans(n);
        vector<int> st;
        for(int i=0;i<n;i++){
            while(!st.empty() && T[st.back()]<T[i]){
                int j=st.back(); st.pop_back();
                ans[j]=i-j;
            }
            st.push_back(i);
        }
        return ans;
    }
};

