int* dailyTemperatures(int* T, int n, int* retSize) {
    int* ans = calloc(n, 4); int* st = malloc(n * 4); int top = 0;
    for (int i = 0; i < n; i++) {
        while (top && T[st[top-1]] < T[i]) {
            int j = st[--top]; ans[j] = i - j;
        }
        st[top++] = i;
    }
    *retSize = n; free(st); return ans;
}
